package algorithms

import (
	"sort"
	"sync"
)

func MergeSort(arr []int) []int {
	if len(arr) <= 1 {
		return arr
	}

	mid := len(arr) / 2
	left := make([]int, mid)
	right := make([]int, len(arr)-mid)

	copy(left, arr[:mid])
	copy(right, arr[mid:])

	var wg sync.WaitGroup
	wg.Add(2)

	go func() {
		defer wg.Done()
		left = MergeSort(left)
	}()

	go func() {
		defer wg.Done()
		right = MergeSort(right)
	}()

	wg.Wait()
	return merge(left, right)
}

func merge(left, right []int) []int {
	result := make([]int, 0, len(left)+len(right))
	i, j := 0, 0

	for i < len(left) && j < len(right) {
		if left[i] <= right[j] {
			result = append(result, left[i])
			i++
		} else {
			result = append(result, right[j])
			j++
		}
	}

	result = append(result, left[i:]...)
	result = append(result, right[j:]...)

	return result
}

func ParallelMergeSort(arr []int, threshold int) []int {
	if len(arr) <= threshold {
		sort.Ints(arr)
		return arr
	}

	mid := len(arr) / 2
	left := make([]int, mid)
	right := make([]int, len(arr)-mid)
	copy(left, arr[:mid])
	copy(right, arr[mid:])

	var wg sync.WaitGroup
	wg.Add(2)

	go func() {
		defer wg.Done()
		left = ParallelMergeSort(left, threshold)
	}()

	go func() {
		defer wg.Done()
		right = ParallelMergeSort(right, threshold)
	}()

	wg.Wait()
	return merge(left, right)
}

package algorithms

import (
	"container/heap"
	"math"
)

type Edge struct {
	To     int
	Weight float64
}

type Graph map[int][]Edge

type Item struct {
	Index    int
	Node     int
	Distance float64
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int            { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool  { return pq[i].Distance < pq[j].Distance }
func (pq PriorityQueue) Swap(i, j int)       { pq[i], pq[j] = pq[j], pq[i]; pq[i].Index = i; pq[j].Index = j }
func (pq *PriorityQueue) Push(x interface{}) { n := len(*pq); item := x.(*Item); item.Index = n; *pq = append(*pq, item) }
func (pq *PriorityQueue) Pop() interface{}   { old := *pq; n := len(old); item := old[n-1]; old[n-1] = nil; *pq = old[:n-1]; return item }

func Dijkstra(graph Graph, start int) map[int]float64 {
	distances := make(map[int]float64)
	for node := range graph {
		distances[node] = math.Inf(1)
	}
	distances[start] = 0

	pq := &PriorityQueue{}
	heap.Init(pq)
	heap.Push(pq, &Item{Node: start, Distance: 0})

	visited := make(map[int]bool)

	for pq.Len() > 0 {
		current := heap.Pop(pq).(*Item)
		if visited[current.Node] {
			continue
		}
		visited[current.Node] = true

		for _, edge := range graph[current.Node] {
			newDist := current.Distance + edge.Weight
			if newDist < distances[edge.To] {
				distances[edge.To] = newDist
				heap.Push(pq, &Item{Node: edge.To, Distance: newDist})
			}
		}
	}

	return distances
}

func FindShortestPath(graph Graph, start, end int) ([]int, float64) {
	distances := Dijkstra(graph, start)
	path := reconstructPath(graph, start, end, distances)
	return path, distances[end]
}

func reconstructPath(graph Graph, start, end int, distances map[int]float64) []int {
	path := []int{end}
	current := end
	for current != start {
		bestPrev := -1
		bestDist := math.Inf(1)
		for _, edge := range graph[current] {
			candidate := distances[edge.To] + edge.Weight
			if candidate < bestDist {
				bestDist = candidate
				bestPrev = edge.To
			}
		}
		if bestPrev == -1 {
			break
		}
		path = append(path, bestPrev)
		current = bestPrev
	}
	reverse(path)
	return path
}

func reverse(arr []int) {
	for i, j := 0, len(arr)-1; i < j; i, j = i+1, j-1 {
		arr[i], arr[j] = arr[j], arr[i]
	}
}

