type TrieNode struct {
	children map[rune]*TrieNode
	isEnd    bool
	value    string
}

type Trie struct {
	root *TrieNode
}

func NewTrie() *Trie {
	return &Trie{
		root: &TrieNode{children: make(map[rune]*TrieNode)},
	}
}

func (t *Trie) Insert(word, value string) {
	node := t.root
	for _, char := range word {
		if _, ok := node.children[char]; !ok {
			node.children[char] = &TrieNode{children: make(map[rune]*TrieNode)}
		}
		node = node.children[char]
	}
	node.isEnd = true
	node.value = value
}

func (t *Trie) Search(word string) string {
	node := t.findNode(word)
	if node == nil || !node.isEnd {
		return ""
	}
	return node.value
}

func (t *Trie) StartsWith(prefix string) bool {
	return t.findNode(prefix) != nil
}

func (t *Trie) Autocomplete(prefix string, limit int) []string {
	node := t.findNode(prefix)
	if node == nil {
		return nil
	}

	results := make([]string, 0)
	var dfs func(n *TrieNode, current string)
	dfs = func(n *TrieNode, current string) {
		if len(results) >= limit {
			return
		}
		if n.isEnd {
			results = append(results, prefix+current)
		}
		for char, child := range n.children {
			dfs(child, current+string(char))
		}
	}
	dfs(node, "")
	return results
}

func (t *Trie) findNode(prefix string) *TrieNode {
	node := t.root
	for _, char := range prefix {
		child, ok := node.children[char]
		if !ok {
			return nil
		}
		node = child
	}
	return node
}

func (t *Trie) Delete(word string) bool {
	return t.deleteHelper(t.root, word, 0)
}

func (t *Trie) deleteHelper(node *TrieNode, word string, depth int) bool {
	if depth == len(word) {
		if !node.isEnd {
			return false
		}
		node.isEnd = false
		return len(node.children) == 0
	}

	char := rune(word[depth])
	child, ok := node.children[char]
	if !ok {
		return false
	}

	shouldDelete := t.deleteHelper(child, word, depth+1)
	if shouldDelete {
		delete(node.children, char)
		return !node.isEnd && len(node.children) == 0
	}
	return false
}

package algorithms

import (
	"fmt"
	"sync"
	"time"
)

type Task struct {
	ID   int
	Data string
}

type Result struct {
	TaskID int
	Output string
}

func Producer(numTasks int, jobs chan<- Task, wg *sync.WaitGroup) {
	defer wg.Done()
	for i := 1; i <= numTasks; i++ {
		jobs <- Task{ID: i, Data: fmt.Sprintf("task-%d", i)}
	}
	close(jobs)
}

func Consumer(id int, jobs <-chan Task, results chan<- Result, wg *sync.WaitGroup) {
	defer wg.Done()
	for task := range jobs {
		time.Sleep(50 * time.Millisecond)
		results <- Result{
			TaskID: task.ID,
			Output: fmt.Sprintf("worker-%d processed: %s", id, task.Data),
		}
	}
}

func RunProducerConsumer(numWorkers, numTasks int) []Result {
	jobs := make(chan Task, numTasks)
	results := make(chan Result, numTasks)

	var producerWg, consumerWg sync.WaitGroup

	producerWg.Add(1)
	go Producer(numTasks, jobs, &producerWg)

	for i := 0; i < numWorkers; i++ {
		consumerWg.Add(1)
		go Consumer(i, jobs, results, &consumerWg)
	}

	go func() {
		producerWg.Wait()
		consumerWg.Wait()
		close(results)
	}()

	var output []Result
	for r := range results {
		output = append(output, r)
	}

	return output
}

func main() {
	results := RunProducerConsumer(4, 20)
	for _, r := range results {
		fmt.Println(r.Output)
	}
}

package algorithms

import (
	"context"
	"fmt"
)

type Node struct {
	ID       int
	Neighbors []int
}

type Graph struct {
	Nodes map[int]*Node
}

func NewGraph() *Graph {
	return &Graph{Nodes: make(map[int]*Node)}
}

func (g *Graph) AddNode(id int, neighbors []int) {
	g.Nodes[id] = &Node{ID: id, Neighbors: neighbors}
}

func BFS(ctx context.Context, graph *Graph, start, target int) ([]int, error) {
	visited := make(map[int]bool)
	queue := []int{start}
	parents := make(map[int]int)

	for len(queue) > 0 {
		select {
		case <-ctx.Done():
			return nil, ctx.Err()
		default:
		}

		current := queue[0]
		queue = queue[1:]

		if current == target {
			return reconstructPath(parents, start, target), nil
		}

		if visited[current] {
			continue
		}
		visited[current] = true

		node := graph.Nodes[current]
		if node == nil {
			continue
		}

		for _, neighbor := range node.Neighbors {
			if !visited[neighbor] {
				parents[neighbor] = current
				queue = append(queue, neighbor)
			}
		}
	}

	return nil, fmt.Errorf("target %d not reachable from %d", target, start)
}

func reconstructPath(parents map[int]int, start, target int) []int {
	path := []int{target}
	for target != start {
		parent, ok := parents[target]
		if !ok {
			return nil
		}
		path = append(path, parent)
		target = parent
	}
	reverse(path)
	return path
}

func reverse(arr []int) {
	for i, j := 0, len(arr)-1; i < j; i, j = i+1, j-1 {
		arr[i], arr[j] = arr[j], arr[i]
	}
}

func main() {
	graph := NewGraph()
	graph.AddNode(0, []int{1, 2})
	graph.AddNode(1, []int{0, 3})
	graph.AddNode(2, []int{0, 4})
	graph.AddNode(3, []int{1, 5})
	graph.AddNode(4, []int{2, 5})
	graph.AddNode(5, []int{3, 4})

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	path, err := BFS(ctx, graph, 0, 5)
	if err != nil {
		fmt.Println(err)
		return
	}
	fmt.Printf("Path: %v\n", path)
}

package algorithms

import (
	"container/list"
	"sync"
)

type lruEntry struct {
	key   string
	value interface{}
}

type LRUCache struct {
	mu       sync.Mutex
	capacity int
	cache    map[string]*list.Element
	order    *list.List
}

func NewLRUCache(capacity int) *LRUCache {
	return &LRUCache{
		capacity: capacity,
		cache:    make(map[string]*list.Element),
		order:    list.New(),
	}
}

func (c *LRUCache) Get(key string) (interface{}, bool) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if elem, ok := c.cache[key]; ok {
		c.order.MoveToFront(elem)
		return elem.Value.(*lruEntry).value, true
	}
	return nil, false
}

func (c *LRUCache) Put(key string, value interface{}) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if elem, ok := c.cache[key]; ok {
		elem.Value.(*lruEntry).value = value
		c.order.MoveToFront(elem)
		return
	}

	if c.order.Len() >= c.capacity {
		back := c.order.Back()
		if back != nil {
			c.order.Remove(back)
			delete(c.cache, back.Value.(*lruEntry).key)
		}
	}

	entry := &lruEntry{key: key, value: value}
	elem := c.order.PushFront(entry)
	c.cache[key] = elem
}

func (c *LRUCache) Delete(key string) bool {
	c.mu.Lock()
	defer c.mu.Unlock()

	if elem, ok := c.cache[key]; ok {
		c.order.Remove(elem)
		delete(c.cache, key)
		return true
	}
	return false
}

func (c *LRUCache) Size() int {
	c.mu.Lock()
	defer c.mu.Unlock()
	return c.order.Len()
}

